"use client";

import { useEffect, useMemo, useState } from 'react';
import { useRouter } from 'next/navigation';
import { format, isToday } from 'date-fns';
import { AnimatePresence, motion } from 'framer-motion';
import {
  Bell,
  CheckCircle2,
  Clock,
  FileText,
  MessageCircle,
  RefreshCw,
  Search,
  Video,
  Zap,
} from 'lucide-react';
import { Appointment, Doctor } from '@/types';
import { appointmentService } from '@/services/appointmentService';
import { chatService } from '@/services/chatService';
import { doctorService } from '@/services/doctorService';
import { subscribeToDoctorQueue } from '@/services/queueService';
import { useAuthStore } from '@/store';
import { useToast } from '@/hooks/use-toast';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Input } from '@/components/ui/input';
import { Skeleton } from '@/components/ui/skeleton';
import { Switch } from '@/components/ui/switch';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import VideoConsultModal from '@/components/doctor/VideoConsultModal';
import { useRecordsStore } from '@/store/recordsStore';
import {
  sendPrescription,
  sendLabRequest,
  sendMedicalCertificate,
} from '../../../../features/doctor/consult/actions';
import {
  markDone,
  nextPatient,
  startConsult,
} from '../../../../features/doctor/queue/actions';

const waitMinutesPerPatient = 12;
const ENABLE_QUEUE_MOCKS = process.env.NEXT_PUBLIC_QUEUE_MOCKS === 'true';
const MOCK_PATIENTS_PLACEHOLDER: { id: string; name: string; avatar?: string; dateOfBirth?: string; gender?: string }[] = [];
const complaintPool = [
  'Fever and cough for 2 days',
  'Headache with dizziness',
  'Sore throat and body aches',
  'Stomach pain after meals',
  'Skin rashes on arms',
  'High blood pressure follow-up',
];

const getAgeLabel = (dateOfBirth?: string) => {
  if (!dateOfBirth) return '—';
  const dob = new Date(dateOfBirth);
  if (Number.isNaN(dob.getTime())) return '—';
  const diff = Date.now() - dob.getTime();
  return Math.max(0, Math.floor(diff / (365.25 * 24 * 60 * 60 * 1000))).toString();
};

const getGenderLabel = (gender?: string) => {
  if (!gender) return '—';
  return gender.charAt(0).toUpperCase() + gender.slice(1);
};

export default function DoctorQueuePage() {
  const router = useRouter();
  const { toast } = useToast();
  const { user, setUser } = useAuthStore();
  const { addPrescriptionFromConsult, addLabResultFromConsult, addCertificateFromConsult } = useRecordsStore();

  const doctor = user as Doctor | null;
  const doctorId = doctor?.userId ?? doctor?.id;
  const onDemand = doctor?.isOnDemand ?? false;

  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPatientId, setCurrentPatientId] = useState<string | null>(null);
  const [showVideo, setShowVideo] = useState(false);
  const [sortBy, setSortBy] = useState<'arrival' | 'time'>('arrival');
  const [searchQuery, setSearchQuery] = useState('');
  const [notesAppointment, setNotesAppointment] = useState<Appointment | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [seeded, setSeeded] = useState(false);

  const [videoRoomUrl, setVideoRoomUrl] = useState<string | undefined>();

  const currentPatient = useMemo(
    () => appointments.find((apt) => apt.id === currentPatientId) ?? null,
    [appointments, currentPatientId]
  );

  const queueWaiting = useMemo(
    () =>
      appointments
        .filter((apt) => apt.status === 'confirmed' && apt.id !== currentPatientId)
        .sort((a, b) => {
          if (a.queueNumber && b.queueNumber) return a.queueNumber - b.queueNumber;
          return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
        }),
    [appointments, currentPatientId]
  );

  const waitingPatients = useMemo(() => {
    const list = searchQuery
      ? queueWaiting.filter((apt) =>
          apt.patient?.name?.toLowerCase().includes(searchQuery.toLowerCase())
        )
      : queueWaiting;
    if (sortBy === 'time') {
      return [...list].sort((a, b) => a.time.localeCompare(b.time));
    }
    return list;
  }, [queueWaiting, searchQuery, sortBy]);

  const completedCount = appointments.filter((apt) => apt.status === 'completed').length;
  const hasQueue = Boolean(currentPatient) || queueWaiting.length > 0;

  const seedQueue = async () => {
    if (!doctorId || seeded || !ENABLE_QUEUE_MOCKS) {
      if (!seeded && !ENABLE_QUEUE_MOCKS) {
        setSeeded(true);
      }
      return;
    }
    const today = new Date().toISOString().split('T')[0];
    const slots = ['09:00', '09:20', '09:40'];

    await Promise.all(
      MOCK_PATIENTS_PLACEHOLDER.slice(0, 3).map(async (patient, index) => {
        const res = await appointmentService.createAppointment({
          patientId: patient.id,
          doctorId,
          date: today,
          time: slots[index % slots.length],
          type: index % 2 === 0 ? 'online' : 'in-clinic',
          symptoms: complaintPool[index % complaintPool.length],
        });
        if (!res.success) return;
        await appointmentService.updateAppointmentStatus(res.data.id, 'confirmed');
      })
    );

    setSeeded(true);
  };

  const loadQueue = async (seedIfEmpty = false) => {
    if (!doctorId) return;
    setLoading(true);
    const res = await appointmentService.getAppointments({ doctorId });
    if (res.success) {
      let todayApts = res.data.filter((apt) => isToday(new Date(apt.date)));
      if (todayApts.length === 0 && seedIfEmpty && ENABLE_QUEUE_MOCKS) {
        await seedQueue();
        const seededRes = await appointmentService.getAppointments({ doctorId });
        if (seededRes.success) {
          todayApts = seededRes.data.filter((apt) => isToday(new Date(apt.date)));
        }
      }
      setAppointments(todayApts);
      const inProgress = todayApts.find((apt) => apt.status === 'in-progress');
      const firstWaiting = todayApts.find((apt) => apt.status === 'confirmed');
      setCurrentPatientId(inProgress?.id ?? firstWaiting?.id ?? null);
      setLastUpdated(new Date());
    }
    setLoading(false);
  };

  useEffect(() => {
    loadQueue(true);
  }, [doctorId]);

  useEffect(() => {
    if (!doctorId || ENABLE_QUEUE_MOCKS) return;
    const ws = subscribeToDoctorQueue(doctorId, () => {
      loadQueue(false);
      setLastUpdated(new Date());
    });
    return () => ws?.close();
  }, [doctorId]); // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    if (!appointments.length) {
      setCurrentPatientId(null);
      return;
    }
    if (currentPatientId && appointments.some((apt) => apt.id === currentPatientId)) return;
    const inProgress = appointments.find((apt) => apt.status === 'in-progress');
    const firstWaiting = appointments.find((apt) => apt.status === 'confirmed');
    setCurrentPatientId(inProgress?.id ?? firstWaiting?.id ?? null);
  }, [appointments, currentPatientId]);

  useEffect(() => {
    if (!doctorId || !onDemand || !ENABLE_QUEUE_MOCKS) return;
    const interval = setInterval(() => {
      const today = new Date().toISOString().split('T')[0];
      const queuePatientIds = appointments
        .filter((apt) => apt.date === today && ['confirmed', 'in-progress'].includes(apt.status))
        .map((apt) => apt.patientId);
      const pool = MOCK_PATIENTS_PLACEHOLDER.filter((patient) => !queuePatientIds.includes(patient.id));
      const patient = (pool.length ? pool : MOCK_PATIENTS_PLACEHOLDER)[
        Math.floor(Math.random() * (pool.length || MOCK_PATIENTS_PLACEHOLDER.length))
      ];
      if (!patient) return;
      const symptoms = complaintPool[Math.floor(Math.random() * complaintPool.length)];
      const now = new Date();
      const time = format(now, 'HH:mm');
      const type = Math.random() > 0.35 ? 'online' : 'in-clinic';

      appointmentService
        .createAppointment({
          patientId: patient.id,
          doctorId,
          date: today,
          time,
          type,
          symptoms,
        })
        .then(async (res) => {
          if (!res.success) return;
          await appointmentService.updateAppointmentStatus(res.data.id, 'confirmed');
          setAppointments((prev) => [
            {
              ...res.data,
              status: 'confirmed',
              patient,
            },
            ...prev,
          ]);
          setLastUpdated(new Date());
          toast({
            title: 'New patient joined the queue',
            description: `${patient.name} - ${symptoms}`,
          });
        });
    }, 30000);

    return () => clearInterval(interval);
  }, [appointments, doctorId, onDemand, toast]);

  const ensureConversationId = async (appointment: Appointment) => {
    if (!user) return null;
    const convRes = await chatService.createConversation(appointment.patientId, user.id, 'doctor');
    return convRes.success ? convRes.data.id : null;
  };

  const handleOnDemand = async (value: boolean) => {
    if (!doctor) return;
    const res = await doctorService.updateOnDemand(doctor.id, value);
    if (res.success) {
      setUser({ ...doctor, isOnDemand: value } as Doctor);
      toast({
        title: value ? 'On-demand enabled' : 'On-demand paused',
        description: value ? 'Patients can consult you instantly.' : 'You are hidden from Consult Now.',
      });
    }
  };

  const updateAppointment = (id: string, data: Partial<Appointment>) => {
    setAppointments((prev) => prev.map((apt) => (apt.id === id ? { ...apt, ...data } : apt)));
  };

  const handleStartConsultation = async (appointment?: Appointment) => {
    const target = appointment ?? currentPatient;
    if (!target) return;
    try {
      let roomUrl = target.videoRoomUrl;
      if (target.status !== 'in-progress' && target.status !== 'in_progress') {
        const updatedApt = await startConsult(target.id) as Appointment;
        roomUrl = updatedApt?.videoRoomUrl ?? roomUrl;
        updateAppointment(target.id, { status: 'in-progress', videoRoomUrl: roomUrl });
      }
      if (!roomUrl && target.type === 'online') {
        const res = await appointmentService.startVideoConsult(target.id);
        if (res.success) {
          roomUrl = res.data.videoRoomUrl;
          updateAppointment(target.id, { videoRoomUrl: roomUrl });
        }
      }
      setVideoRoomUrl(roomUrl);
      setCurrentPatientId(target.id);
      setShowVideo(true);
      setLastUpdated(new Date());
    } catch (err) {
      toast({
        title: 'Failed to start consultation',
        description: err instanceof Error ? err.message : 'Please try again.',
        variant: 'destructive',
      });
    }
  };

  const handleCallNext = async (appointment?: Appointment) => {
    if (currentPatient?.status === 'in-progress') {
      toast({
        title: 'Finish current consult first',
        description: 'Mark done before calling the next patient.',
      });
      return;
    }
    const next = appointment ?? queueWaiting[0];
    if (!next) return;
    await nextPatient(next.id);
    updateAppointment(next.id, { status: 'in-progress' });
    setCurrentPatientId(next.id);
    setLastUpdated(new Date());
    toast({ title: `Calling ${next.patient?.name}` });
  };

  const handleCompleteConsultation = async (appointment?: Appointment, notes?: string) => {
    const target = appointment ?? currentPatient;
    if (!target) return;
    await markDone(target.id, notes);
    updateAppointment(target.id, { status: 'completed' });
    if (currentPatientId === target.id) {
      setCurrentPatientId(queueWaiting[0]?.id ?? null);
    }
    setLastUpdated(new Date());
    toast({
      title: 'Consultation completed',
      description: queueWaiting[0]?.patient?.name
        ? `Next patient: ${queueWaiting[0].patient?.name}`
        : 'Queue is empty',
    });
  };

  const handleMessagePatient = async (appointment: Appointment) => {
    const conversationId = await ensureConversationId(appointment);
    if (conversationId) {
      router.push(`/doctor/messages?conversation=${conversationId}`);
    }
  };

  const handleSendPrescription = async (payload: { diagnosis: string; medications: string; instructions: string }) => {
    if (!currentPatient || !user) return;
    try {
      const rx = await sendPrescription({
        appointmentId: currentPatient.id,
        patientId: currentPatient.patientId,
        doctorId: user.id,
        diagnosis: payload.diagnosis,
        medications: payload.medications,
        instructions: payload.instructions,
      });
      addPrescriptionFromConsult(rx);
      const conversationId = await ensureConversationId(currentPatient);
      if (conversationId) {
        await chatService.sendMessage(
          conversationId,
          user.id,
          'doctor',
          'E-prescription sent. Please check My Files.',
          'prescription'
        );
      }
      toast({ title: 'Prescription sent', description: 'Patient received the e-prescription.' });
    } catch (error) {
      toast({
        title: 'Failed to send prescription',
        description: error instanceof Error ? error.message : 'Please try again.',
        variant: 'destructive',
      });
    }
  };

  const handleSendLab = async (payload: { testName: string; notes: string }) => {
    if (!currentPatient || !user) return;
    try {
      const lab = await sendLabRequest({
        appointmentId: currentPatient.id,
        patientId: currentPatient.patientId,
        doctorId: user.id,
        testName: payload.testName,
        notes: payload.notes,
      });
      addLabResultFromConsult(lab);
      const conversationId = await ensureConversationId(currentPatient);
      if (conversationId) {
        await chatService.sendMessage(conversationId, user.id, 'doctor', 'Lab request sent. Please check My Files.', 'file');
      }
      toast({ title: 'Lab request sent', description: 'Lab request added to patient files.' });
    } catch (error) {
      toast({
        title: 'Failed to send lab request',
        description: error instanceof Error ? error.message : 'Please try again.',
        variant: 'destructive',
      });
    }
  };

  const handleSendCertificate = async (payload: { purpose: string; diagnosis: string; restDays: number }) => {
    if (!currentPatient || !user) return;
    try {
      const cert = await sendMedicalCertificate({
        appointmentId: currentPatient.id,
        patientId: currentPatient.patientId,
        doctorId: user.id,
        purpose: payload.purpose,
        diagnosis: payload.diagnosis,
        restDays: payload.restDays,
      });
      addCertificateFromConsult(cert);
      const conversationId = await ensureConversationId(currentPatient);
      if (conversationId) {
        await chatService.sendMessage(conversationId, user.id, 'doctor', 'Medical certificate issued. Please check My Files.', 'file');
      }
      toast({ title: 'Medical certificate sent', description: 'Certificate added to patient files.' });
    } catch (error) {
      toast({
        title: 'Failed to send certificate',
        description: error instanceof Error ? error.message : 'Please try again.',
        variant: 'destructive',
      });
    }
  };

  return (
    <div className="space-y-6">
      <motion.div
        initial={{ opacity: 0, y: -8 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col xl:flex-row xl:items-center justify-between gap-4"
      >
        <div>
          <h1 className="text-2xl font-bold text-foreground">Doctor Queue</h1>
          <p className="text-sm text-muted-foreground">{format(new Date(), 'EEEE, MMMM d, yyyy')}</p>
          <div className="flex flex-wrap items-center gap-2 mt-3">
            <Badge className="bg-primary/10 text-primary border-primary/20">
              {queueWaiting.length} waiting
            </Badge>
            <Badge variant="secondary">
              {completedCount} completed
            </Badge>
            <Badge variant="outline" className="text-xs">
              Last updated {lastUpdated ? format(lastUpdated, 'p') : '--'}
            </Badge>
          </div>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-2 rounded-full bg-secondary/60 px-3 py-1.5">
            <Switch checked={onDemand} onCheckedChange={handleOnDemand} id="doctor-on-demand-queue" />
            <label htmlFor="doctor-on-demand-queue" className="text-xs text-muted-foreground">
              On-Demand: {onDemand ? 'Available' : 'Paused'}
            </label>
          </div>
          <Badge className={onDemand ? 'bg-success/15 text-success border-success/30' : 'bg-muted text-muted-foreground border-border'}>
            <span className={`mr-1 h-2 w-2 rounded-full ${onDemand ? 'bg-success animate-pulse' : 'bg-muted-foreground/50'}`} />
            {onDemand ? 'Live' : 'Offline'}
          </Badge>
          <Button variant="outline" size="sm" className="gap-1.5" onClick={() => loadQueue(false)}>
            <RefreshCw className="h-4 w-4" />
            Refresh
          </Button>
        </div>
      </motion.div>

      <div className="grid lg:grid-cols-[2fr_1fr] gap-6">
        <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}>
          <Card className="border-primary/20 bg-primary/5">
            <CardHeader className="flex flex-row items-center justify-between">
              <CardTitle className="text-lg">Now Serving</CardTitle>
              {currentPatient ? (
                <Badge className="bg-success/15 text-success border-success/30">Now Serving</Badge>
              ) : (
                <Badge variant="secondary">Idle</Badge>
              )}
            </CardHeader>
            <CardContent className="space-y-4">
              {loading ? (
                <div className="space-y-4">
                  <Skeleton className="h-20 w-full rounded-xl" />
                  <Skeleton className="h-10 w-3/4 rounded-xl" />
                </div>
              ) : currentPatient ? (
                <div className="space-y-4">
                  <div className="flex flex-col sm:flex-row sm:items-center gap-4 p-4 rounded-xl bg-background border border-border">
                    <Avatar className="h-16 w-16">
                      <AvatarImage src={currentPatient.patient?.avatar} />
                      <AvatarFallback>{currentPatient.patient?.name?.[0]}</AvatarFallback>
                    </Avatar>
                    <div className="flex-1 space-y-1">
                      <div className="flex flex-wrap items-center gap-2">
                        <p className="text-lg font-semibold text-foreground">{currentPatient.patient?.name}</p>
                        <Badge variant="secondary" className="text-xs">
                          {currentPatient.type === 'online' ? 'Video Consult' : 'In-Clinic'}
                        </Badge>
                        <Badge className="bg-primary/10 text-primary border-primary/20 text-xs">
                          Queue #{currentPatient.queueNumber ?? 1}
                        </Badge>
                      </div>
                      <p className="text-xs text-muted-foreground">
                        {getAgeLabel(currentPatient.patient?.dateOfBirth)} yrs • {getGenderLabel(currentPatient.patient?.gender)}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        Arrived {format(new Date(currentPatient.createdAt), 'p')}
                      </p>
                      {currentPatient.symptoms && (
                        <p className="text-sm text-muted-foreground mt-2">
                          Reason: {currentPatient.symptoms}
                        </p>
                      )}
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-2">
                    {currentPatient.status !== 'in-progress' ? (
                      <Button onClick={() => handleStartConsultation(currentPatient)} className="gap-2">
                        <Video className="h-4 w-4" />
                        Start Video Consult
                      </Button>
                    ) : (
                      <Button onClick={() => { setVideoRoomUrl(currentPatient.videoRoomUrl); setShowVideo(true); }} variant="outline" className="gap-2">
                        <Video className="h-4 w-4" />
                        Open Call
                      </Button>
                    )}
                    <Button variant="outline" onClick={() => handleCallNext()} className="gap-2">
                      <Bell className="h-4 w-4" />
                      Call Next
                    </Button>
                    <Button
                      variant="outline"
                      onClick={() => handleMessagePatient(currentPatient)}
                      className="gap-2"
                    >
                      <MessageCircle className="h-4 w-4" />
                      Message Patient
                    </Button>
                    <Button variant="outline" onClick={() => setNotesAppointment(currentPatient)} className="gap-2">
                      <FileText className="h-4 w-4" />
                      View Notes
                    </Button>
                    <Button onClick={() => handleCompleteConsultation(currentPatient)} className="gap-2">
                      <CheckCircle2 className="h-4 w-4" />
                      Mark Done
                    </Button>
                  </div>
                </div>
              ) : hasQueue ? (
                <div className="text-center py-10 text-muted-foreground space-y-3">
                  <Clock className="h-12 w-12 mx-auto opacity-40" />
                  <p className="text-sm">No patient is active. Call the next patient to begin.</p>
                  <Button size="sm" className="gap-2" onClick={() => handleCallNext()}>
                    <Bell className="h-4 w-4" />
                    Call Next Patient
                  </Button>
                </div>
              ) : (
                <div className="text-center py-10 text-muted-foreground space-y-3">
                  <CheckCircle2 className="h-12 w-12 mx-auto text-success" />
                  <p className="text-sm">No patients in queue.</p>
                  <Button size="sm" className="gap-2" onClick={() => handleOnDemand(true)}>
                    <Zap className="h-4 w-4" />
                    Go On-Demand
                  </Button>
                </div>
              )}
            </CardContent>
          </Card>
        </motion.div>

        <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.05 }}>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <CardTitle className="text-lg">Waiting List</CardTitle>
              <Badge variant="secondary">{waitingPatients.length}</Badge>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Search patient in queue..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-10"
                />
              </div>

              <div className="flex flex-wrap gap-2">
                <Button
                  size="sm"
                  variant={sortBy === 'arrival' ? 'default' : 'outline'}
                  onClick={() => setSortBy('arrival')}
                >
                  Arrival Order
                </Button>
                <Button
                  size="sm"
                  variant={sortBy === 'time' ? 'default' : 'outline'}
                  onClick={() => setSortBy('time')}
                >
                  By Time
                </Button>
              </div>

              {loading ? (
                <div className="space-y-3">
                  {[1, 2, 3].map((i) => (
                    <Skeleton key={i} className="h-20 rounded-xl" />
                  ))}
                </div>
              ) : waitingPatients.length === 0 ? (
                <div className="text-sm text-muted-foreground text-center py-6">
                  No patients waiting
                </div>
              ) : (
                <div className="space-y-3">
                  <AnimatePresence>
                    {waitingPatients.map((apt, index) => {
                      const waitMinutes = Math.max(waitMinutesPerPatient, (index + 1) * waitMinutesPerPatient);
                      return (
                        <motion.div
                          key={apt.id}
                          initial={{ opacity: 0, y: 10 }}
                          animate={{ opacity: 1, y: 0 }}
                          exit={{ opacity: 0, y: -10 }}
                          className="group rounded-xl border border-border bg-background p-3 hover:border-primary/20 transition-colors"
                        >
                          <div className="flex items-start gap-3">
                            <span className="text-xs text-muted-foreground w-6">#{index + 1}</span>
                            <Avatar className="h-10 w-10">
                              <AvatarImage src={apt.patient?.avatar} />
                              <AvatarFallback>{apt.patient?.name?.[0]}</AvatarFallback>
                            </Avatar>
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-2">
                                <p className="text-sm font-semibold text-foreground truncate">
                                  {apt.patient?.name}
                                </p>
                                <Badge variant="secondary" className="text-[10px]">
                                  {apt.type === 'online' ? 'Video' : 'In-Clinic'}
                                </Badge>
                              </div>
                              <p className="text-xs text-muted-foreground">
                                {getAgeLabel(apt.patient?.dateOfBirth)} yrs • {getGenderLabel(apt.patient?.gender)}
                              </p>
                              <p className="text-xs text-muted-foreground line-clamp-1">
                                Reason: {apt.symptoms || 'General consultation'}
                              </p>
                              <div className="flex flex-wrap items-center gap-3 mt-2 text-xs text-muted-foreground">
                                <span className="flex items-center gap-1">
                                  <Clock className="h-3 w-3" />
                                  Arrived {format(new Date(apt.createdAt), 'p')}
                                </span>
                                <span className="flex items-center gap-1">
                                  <Bell className="h-3 w-3" />
                                  Est wait {waitMinutes} min
                                </span>
                              </div>
                            </div>
                          </div>
                          <div className="mt-3 flex flex-wrap gap-2 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                            <Button size="sm" className="gap-1.5" onClick={() => handleStartConsultation(apt)}>
                              <Video className="h-3.5 w-3.5" />
                              Start Video
                            </Button>
                            <Button size="sm" variant="outline" className="gap-1.5" onClick={() => handleCallNext(apt)}>
                              <Bell className="h-3.5 w-3.5" />
                              Call Next
                            </Button>
                            <Button size="sm" variant="outline" className="gap-1.5" onClick={() => handleMessagePatient(apt)}>
                              <MessageCircle className="h-3.5 w-3.5" />
                              Message
                            </Button>
                            <Button size="sm" variant="outline" className="gap-1.5" onClick={() => setNotesAppointment(apt)}>
                              <FileText className="h-3.5 w-3.5" />
                              View Notes
                            </Button>
                            <Button size="sm" variant="ghost" className="gap-1.5 text-success" onClick={() => handleCompleteConsultation(apt)}>
                              <CheckCircle2 className="h-3.5 w-3.5" />
                              Mark Done
                            </Button>
                          </div>
                        </motion.div>
                      );
                    })}
                  </AnimatePresence>
                </div>
              )}
            </CardContent>
          </Card>
        </motion.div>
      </div>

      <VideoConsultModal
        open={showVideo}
        appointment={currentPatient}
        videoRoomUrl={videoRoomUrl}
        onClose={() => { setShowVideo(false); setVideoRoomUrl(undefined); }}
        onEnd={(notes) => {
          setShowVideo(false);
          setVideoRoomUrl(undefined);
          handleCompleteConsultation(currentPatient ?? undefined, notes);
        }}
        onSendPrescription={handleSendPrescription}
        onSendLab={handleSendLab}
        onSendCertificate={handleSendCertificate}
      />

      <Dialog open={Boolean(notesAppointment)} onOpenChange={(open) => !open && setNotesAppointment(null)}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Patient Notes</DialogTitle>
          </DialogHeader>
          {notesAppointment ? (
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                <Avatar className="h-10 w-10">
                  <AvatarImage src={notesAppointment.patient?.avatar} />
                  <AvatarFallback>{notesAppointment.patient?.name?.[0]}</AvatarFallback>
                </Avatar>
                <div>
                  <p className="font-medium text-foreground">{notesAppointment.patient?.name}</p>
                  <p className="text-xs text-muted-foreground">
                    {notesAppointment.time} • {notesAppointment.type === 'online' ? 'Video' : 'In-Clinic'}
                  </p>
                </div>
              </div>
              <div className="rounded-lg border border-border p-3">
                <p className="text-xs text-muted-foreground mb-1">Chief complaint</p>
                <p className="text-sm text-foreground">
                  {notesAppointment.symptoms || 'No symptoms recorded yet.'}
                </p>
              </div>
              <div className="rounded-lg border border-border p-3">
                <p className="text-xs text-muted-foreground mb-1">Doctor notes</p>
                <p className="text-sm text-foreground">
                  {notesAppointment.notes || 'No notes added yet.'}
                </p>
              </div>
              <div className="flex gap-2">
                <Button variant="outline" onClick={() => handleMessagePatient(notesAppointment)}>
                  Message Patient
                </Button>
                <Button onClick={() => handleStartConsultation(notesAppointment)}>
                  Start Consult
                </Button>
              </div>
            </div>
          ) : null}
        </DialogContent>
      </Dialog>
    </div>
  );
}
